const input = $input.first().json;
const query = String(input.query || '').trim();
const args = query ? { query, limit: 25 } : { limit: 25 };
return [{
  json: {
    query,
    rpc: { jsonrpc: '2.0', id: 1, method: 'tools/call', params: { name: 'search_workflows', arguments: args } },
  },
}];

function parseMcpSse(raw) {
  const text = typeof raw === 'string' ? raw : String(raw ?? '');
  const dataLine = text.split(/\r?\n/).find((l) => l.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP search response: ' + text.slice(0, 500));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const t = payload.result?.content?.[0]?.text;
  return t ? JSON.parse(t) : (payload.result?.structuredContent || {});
}
const data = parseMcpSse($input.first().json.body ?? $input.first().json.data ?? '');
const items = Array.isArray(data) ? data : (data.data || data.workflows || data.results || data.items || []);
const query = ($('Build Search RPC').first().json.query || '').toLowerCase();
const filtered = query ? items.filter((w) => ((w.name || '') + ' ' + (w.description || '')).toLowerCase().includes(query)) : items;
const rows = filtered.map((w) => ({
  id: w.id || w.workflowId || '',
  name: w.name || '(unnamed)',
  active: !!w.active,
  url: w.url || (w.id ? `http://localhost:5678/workflow/${w.id}` : ''),
  description: w.description || w.summary || '',
}));
const lines = rows.map((r, i) => `${i + 1}. ${r.name}${r.active ? ' (active)' : ''} - ${r.url}${r.description ? `\n   ${r.description}` : ''}`);
const response = rows.length
  ? `Found ${rows.length} workflow${rows.length === 1 ? '' : 's'}:\n${lines.join('\n')}`
  : (query ? `No workflows match "${query}".` : 'No workflows found.');
return [{ json: { count: rows.length, workflows: rows, response } }];
